const summary = $json || {};

function money(v) {
  const n = Number(v || 0);
  if (Number.isNaN(n)) return 'R0.00';
  return 'R' + n.toLocaleString('en-ZA', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function clean(v) {
  return String(v == null ? '' : v).trim();
}

if (summary.success !== true) {
  throw new Error('Daily summary endpoint did not return success=true.');
}

const counts = summary.counts || {};
const sections = summary.sections || {};
const attention = Array.isArray(sections.orders_needing_attention) ? sections.orders_needing_attention : [];
const pending = Array.isArray(sections.pending_approval) ? sections.pending_approval : [];
const approved = Array.isArray(sections.approved) ? sections.approved : [];

const lines = [];
lines.push('Amadeus Daily Order Summary');
lines.push('Date: ' + clean(summary.report_date));
lines.push('');
lines.push('Counts');
lines.push('New drafts: ' + (counts.new_drafts || 0));
lines.push('Drafts missing payment: ' + (counts.drafts_missing_payment_method || 0));
lines.push('Pending approval: ' + (counts.pending_approval || 0));
lines.push('Approved: ' + (counts.approved || 0));
lines.push('Cancelled today: ' + (counts.cancelled_today || 0));
lines.push('Completed today: ' + (counts.completed_today || 0));
lines.push('Needs attention: ' + (counts.orders_needing_attention || 0));

if (attention.length > 0) {
  lines.push('');
  lines.push('Needs Attention');
  attention.slice(0, 8).forEach((order, index) => {
    const reasons = Array.isArray(order.reasons) ? order.reasons.join(', ') : '';
    lines.push(`${index + 1}. ${clean(order.order_id)} | ${clean(order.customer_name) || '-'} | ${clean(order.order_status) || '-'} | ${reasons || 'review'} | ${money(order.active_line_total)}`);
  });
  if (attention.length > 8) lines.push(`...and ${attention.length - 8} more.`);
}

if (pending.length > 0) {
  lines.push('');
  lines.push('Pending Approval');
  pending.slice(0, 5).forEach((order, index) => {
    lines.push(`${index + 1}. ${clean(order.order_id)} | ${clean(order.customer_name) || '-'} | ${money(order.active_line_total)}`);
  });
}

if (approved.length > 0) {
  lines.push('');
  lines.push('Approved Orders');
  approved.slice(0, 5).forEach((order, index) => {
    lines.push(`${index + 1}. ${clean(order.order_id)} | ${clean(order.customer_name) || '-'} | reserved ${order.reserved_pig_count || 0}/${order.active_line_count || 0}`);
  });
}

return [{
  json: {
    chat_id: '5721652188',
    message_text: lines.join('\n'),
    report_date: clean(summary.report_date),
    counts
  }
}];
